// 辅助
//==============================================================================

llvm::Value*
EmitIR::createAlloca(llvm::Type* ty, const std::string& name)
{
  // Allocate at the entry block of the current function
  auto& entryBb = mCurFunc->getEntryBlock();
  llvm::IRBuilder<> entryIrb(&entryBb, entryBb.begin());
  return entryIrb.CreateAlloca(ty, nullptr, name);
}

void
EmitIR::storeInit(llvm::Value* ptr, Expr* init, const Type* type)
