void
EmitIR::operator()(FunctionDecl* obj)
{
  auto func = llvm::dyn_cast<llvm::Function>(mDeclMap[obj]);
  if (!func)
    ABORT();

  auto fty = func->getFunctionType();

  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& irb = *mCurIrb;

  // Allocate space for parameters and store them
  auto argIt = func->arg_begin();
  for (size_t i = 0; i < obj->params.size() && argIt != func->arg_end(); ++i, ++argIt) {
    auto param = obj->params[i];
    auto vd = param->dcst<VarDecl>();
    if (vd) {
      auto paramTy = self(vd->type);
      auto alloca = createAlloca(paramTy, vd->name);
      irb.CreateStore(&*argIt, alloca);
      mDeclMap[vd] = alloca;
    }
  }

  mCurFunc = func;
  self(obj->body);

  // Ensure the last block has a terminator
  auto& exitIrb = *mCurIrb;
  auto lastBb = exitIrb.GetInsertBlock();
  if (!lastBb->getTerminator()) {
    if (fty->getReturnType()->isVoidTy())
      exitIrb.CreateRetVoid();
    else
      exitIrb.CreateRet(llvm::ConstantInt::get(fty->getReturnType(), 0));
  }
}

void
EmitIR::operator()(VarDecl* obj, bool isGlobal)
{
  auto& irb = *mCurIrb;
  auto ty = self(obj->type);

  if (isGlobal) {
    llvm::Constant* initVal = nullptr;
    if (obj->init) {
      if (auto il = obj->init->dcst<IntegerLiteral>()) {
        initVal = llvm::ConstantInt::get(ty, il->val);
      } else if (auto ile = obj->init->dcst<ImplicitInitExpr>()) {
        initVal = llvm::ConstantInt::get(ty, 0);
      }
    }
    if (!initVal)
      initVal = llvm::ConstantInt::get(ty, 0);

    auto gv = new llvm::GlobalVariable(
      mMod, ty, false, llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    mDeclMap[obj] = gv;
  } else {
    // Local variable
    auto alloca = createAlloca(ty, obj->name);
    mDeclMap[obj] = alloca;

    if (obj->init) {
      storeInit(alloca, obj->init, obj->type);
    }
  }
}

