   550	  } else if (auto ile = init->dcst<ImplicitInitExpr>()) {
   551	    irb.CreateStore(llvm::ConstantInt::get(self(type), 0), ptr);
   552	  } else if (auto initList = init->dcst<InitListExpr>()) {
   553	    // Handle array initialization
   554	    auto arrTy = llvm::dyn_cast<llvm::ArrayType>(self(type));
   555	    if (arrTy) {
