#include "EmitIR.hpp"
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  // First pass: create all function declarations and global variables
  for (auto&& i : tu->decls) {
    if (auto fd = i->dcst<FunctionDecl>()) {
      auto fty = llvm::dyn_cast<llvm::FunctionType>(self(fd->type));
      auto func = llvm::Function::Create(
        fty, llvm::GlobalVariable::ExternalLinkage, fd->name, mMod);
      fd->any = func;
      mDeclMap[fd] = func;
    }
  }

  // Second pass: emit global variables and function bodies
  for (auto&& i : tu->decls) {
    if (auto vd = i->dcst<VarDecl>()) {
      self(vd, true); // global
    } else if (auto fd = i->dcst<FunctionDecl>()) {
      if (fd->body) {
        self(fd);
      }
    }
  }
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kVoid:
        return llvm::Type::getVoidTy(mCtx);
      case Type::Spec::kChar:
        return llvm::Type::getInt8Ty(mCtx);
      case Type::Spec::kInt:
        return llvm::Type::getInt32Ty(mCtx);
      case Type::Spec::kLong:
      case Type::Spec::kLongLong:
        return llvm::Type::getInt64Ty(mCtx);
      default:
        ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  if (auto p = type->texp->dcst<PointerType>()) {
    return llvm::Type::getPtrTy(mCtx);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    auto elemTy = self(&subt);
    if (p->len == ArrayType::kUnLen)
      return llvm::ArrayType::get(elemTy, 0);
    return llvm::ArrayType::get(elemTy, p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto&& param : p->params) {
      pty.push_back(self(param));
    }
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);
  if (auto p = obj->dcst<ParenExpr>())
    return self(p);
  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);
  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);
  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);
  if (auto p = obj->dcst<InitListExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitInitExpr>())
    return self(p);
  ABORT();
}

llvm::Value*
EmitIR::emitRValue(Expr* obj)
{
  auto val = self(obj);
  // If the expression is an lvalue, load it
  if (obj->cate == Expr::Cate::kLValue) {
    auto& irb = *mCurIrb;
    auto ty = self(obj->type);
    return irb.CreateLoad(ty, val);
  }
  return val;
}

llvm::Value*
EmitIR::emitLValue(Expr* obj)
{
  return self(obj);
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  auto it = mDeclMap.find(decl);
  if (it != mDeclMap.end())
    return it->second;
  ABORT();
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = emitRValue(obj->sub);

  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);
    case UnaryExpr::kNot:
      return irb.CreateICmpEQ(sub, llvm::ConstantInt::get(sub->getType(), 0));
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;

  // Assignment: lft must be lvalue
  if (obj->op == BinaryExpr::kAssign) {
    auto lftPtr = emitLValue(obj->lft);
    auto rhtVal = emitRValue(obj->rht);
    // Cast rht to match lft type if needed
    auto lftTy = self(obj->lft->type);
    if (rhtVal->getType() != lftTy) {
      if (lftTy->isIntegerTy() && rhtVal->getType()->isIntegerTy()) {
        rhtVal = irb.CreateIntCast(rhtVal, lftTy, true);
      }
    }
    irb.CreateStore(rhtVal, lftPtr);
    return rhtVal;
  }

  // Comma: evaluate left, then right, return right
  if (obj->op == BinaryExpr::kComma) {
    emitRValue(obj->lft);
    return emitRValue(obj->rht);
  }

  // Array index: lft[index]
  if (obj->op == BinaryExpr::kIndex) {
    auto lftPtr = emitLValue(obj->lft);
    auto idx = emitRValue(obj->rht);
    // lftPtr is a pointer to array element type
    // We need to GEP into the array
    auto elemTy = self(obj->type);
    return irb.CreateInBoundsGEP(elemTy, lftPtr, idx);
  }

  // Logical AND with short-circuit
  if (obj->op == BinaryExpr::kAnd) {
    auto curBb = irb.GetInsertBlock();
    auto func = curBb->getParent();
    auto trueBb = llvm::BasicBlock::Create(mCtx, "and.true", func);
    auto endBb = llvm::BasicBlock::Create(mCtx, "and.end", func);

    auto lftVal = emitRValue(obj->lft);
    auto lftBool = irb.CreateICmpNE(lftVal, llvm::ConstantInt::get(lftVal->getType(), 0));
    irb.CreateCondBr(lftBool, trueBb, endBb);

    irb.SetInsertPoint(trueBb);
    auto rhtVal = emitRValue(obj->rht);
    auto rhtBool = irb.CreateICmpNE(rhtVal, llvm::ConstantInt::get(rhtVal->getType(), 0));
    auto rhtInt = irb.CreateZExt(rhtBool, mIntTy);
    irb.CreateBr(endBb);

    irb.SetInsertPoint(endBb);
    auto phi = irb.CreatePHI(mIntTy, 2);
    phi->addIncoming(llvm::ConstantInt::get(mIntTy, 0), curBb);
    phi->addIncoming(rhtInt, trueBb);
    return phi;
  }

  // Logical OR with short-circuit
  if (obj->op == BinaryExpr::kOr) {
    auto curBb = irb.GetInsertBlock();
    auto func = curBb->getParent();
    auto falseBb = llvm::BasicBlock::Create(mCtx, "or.false", func);
    auto endBb = llvm::BasicBlock::Create(mCtx, "or.end", func);

    auto lftVal = emitRValue(obj->lft);
    auto lftBool = irb.CreateICmpNE(lftVal, llvm::ConstantInt::get(lftVal->getType(), 0));
    irb.CreateCondBr(lftBool, endBb, falseBb);

    irb.SetInsertPoint(falseBb);
    auto rhtVal = emitRValue(obj->rht);
    auto rhtBool = irb.CreateICmpNE(rhtVal, llvm::ConstantInt::get(rhtVal->getType(), 0));
    auto rhtInt = irb.CreateZExt(rhtBool, mIntTy);
    irb.CreateBr(endBb);

    irb.SetInsertPoint(endBb);
    auto phi = irb.CreatePHI(mIntTy, 2);
    phi->addIncoming(llvm::ConstantInt::get(mIntTy, 1), curBb);
    phi->addIncoming(rhtInt, falseBb);
    return phi;
  }

  // All other binary ops: evaluate both sides
  auto lft = emitRValue(obj->lft);
  auto rht = emitRValue(obj->rht);

  // Ensure both operands have the same type
  if (lft->getType() != rht->getType()) {
    if (lft->getType()->isIntegerTy() && rht->getType()->isIntegerTy()) {
      auto lftW = lft->getType()->getIntegerBitWidth();
      auto rhtW = rht->getType()->getIntegerBitWidth();
      if (lftW > rhtW)
        rht = irb.CreateIntCast(rht, lft->getType(), true);
      else
        lft = irb.CreateIntCast(lft, rht->getType(), true);
    }
  }

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lft, rht);
    case BinaryExpr::kSub:
      return irb.CreateSub(lft, rht);
    case BinaryExpr::kMul:
      return irb.CreateMul(lft, rht);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lft, rht);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lft, rht);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lft, rht);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lft, rht);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lft, rht);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lft, rht);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lft, rht);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lft, rht);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;

  // Get the function - head might be wrapped in ImplicitCastExpr
  Expr* head = obj->head;
  while (auto cast = head->dcst<ImplicitCastExpr>()) {
    head = cast->sub;
  }

  llvm::Value* callee = nullptr;
  if (auto dre = head->dcst<DeclRefExpr>()) {
    callee = self(dre);
  } else {
    callee = emitRValue(head);
  }

  auto func = llvm::dyn_cast<llvm::Function>(callee);
  if (!func) {
    // It's a function pointer
    auto fty = llvm::dyn_cast<llvm::FunctionType>(
      callee->getType()->getPointerElementType());
    if (!fty) {
      // Try to get function type from the head expression
      auto headType = head->type;
      if (auto ft = headType->texp->dcst<FunctionType>()) {
        fty = llvm::dyn_cast<llvm::FunctionType>(self(headType));
      }
    }
  }

  std::vector<llvm::Value*> args;
  auto fty = func ? func->getFunctionType() : nullptr;
  for (size_t i = 0; i < obj->args.size(); ++i) {
    auto arg = emitRValue(obj->args[i]);
    if (fty && i < fty->getNumParams()) {
      auto paramTy = fty->getParamType(i);
      if (arg->getType() != paramTy) {
        if (paramTy->isIntegerTy() && arg->getType()->isIntegerTy()) {
          arg = irb.CreateIntCast(arg, paramTy, true);
        }
      }
    }
    args.push_back(arg);
  }

  if (func)
    return irb.CreateCall(func, args);
  else
    return irb.CreateCall(fty, callee, args);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);

  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue: {
      auto ty = self(obj->type);
      return irb.CreateLoad(ty, sub);
    }
    case ImplicitCastExpr::kIntegralCast: {
      auto targetTy = self(obj->type);
      if (sub->getType() == targetTy)
        return sub;
      if (targetTy->isIntegerTy() && sub->getType()->isIntegerTy())
        return irb.CreateIntCast(sub, targetTy, true);
      return sub;
    }
    case ImplicitCastExpr::kArrayToPointerDecay:
      return sub; // Already a pointer
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return sub; // Already a pointer
    case ImplicitCastExpr::kNoOp:
      return sub;
    default:
      return sub;
  }
}

llvm::Value*
EmitIR::operator()(InitListExpr* obj)
{
  // This should be handled at the declaration level
  ABORT();
}

llvm::Value*
EmitIR::operator()(ImplicitInitExpr* obj)
{
  // Return zero
  return llvm::ConstantInt::get(mIntTy, 0);
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);
  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);
  if (auto p = obj->dcst<ExprStmt>())
    return self(p);
  if (auto p = obj->dcst<NullStmt>())
    return self(p);
  if (auto p = obj->dcst<DeclStmt>())
    return self(p);
  if (auto p = obj->dcst<IfStmt>())
    return self(p);
  if (auto p = obj->dcst<WhileStmt>())
    return self(p);
  if (auto p = obj->dcst<BreakStmt>())
    return self(p);
  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);
  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;

  llvm::Value* retVal;
  if (!obj->expr)
    retVal = nullptr;
  else
    retVal = emitRValue(obj->expr);

  irb.CreateRet(retVal);

  // Create a new block after return (for subsequent code)
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    emitRValue(obj->expr);
}

void
EmitIR::operator()(NullStmt* obj)
{
  // Do nothing
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls) {
    if (auto vd = decl->dcst<VarDecl>()) {
      self(vd, false); // local
    }
  }
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto func = irb.GetInsertBlock()->getParent();

  auto condVal = emitRValue(obj->cond);
  auto condBool = irb.CreateICmpNE(condVal, llvm::ConstantInt::get(condVal->getType(), 0));

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", func);
  auto elseBb = obj->else_ ? llvm::BasicBlock::Create(mCtx, "if.else", func) : nullptr;
  auto mergeBb = llvm::BasicBlock::Create(mCtx, "if.end", func);

  if (elseBb)
    irb.CreateCondBr(condBool, thenBb, elseBb);
  else
    irb.CreateCondBr(condBool, thenBb, mergeBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(mergeBb);

  if (elseBb) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!irb.GetInsertBlock()->getTerminator())
      irb.CreateBr(mergeBb);
  }

  irb.SetInsertPoint(mergeBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;
  auto func = irb.GetInsertBlock()->getParent();

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", func);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", func);
  auto exitBb = llvm::BasicBlock::Create(mCtx, "while.end", func);

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto condVal = emitRValue(obj->cond);
  auto condBool = irb.CreateICmpNE(condVal, llvm::ConstantInt::get(condVal->getType(), 0));
  irb.CreateCondBr(condBool, bodyBb, exitBb);

  mLoopStack.push_back({ condBb, exitBb });
  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  mLoopStack.pop_back();

  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(condBb);

  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!mLoopStack.empty()) {
    irb.CreateBr(mLoopStack.back().exitBb);
    auto deadBb = llvm::BasicBlock::Create(mCtx, "after_break", mCurFunc);
    irb.SetInsertPoint(deadBb);
  }
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!mLoopStack.empty()) {
    irb.CreateBr(mLoopStack.back().condBb);
    auto deadBb = llvm::BasicBlock::Create(mCtx, "after_continue", mCurFunc);
    irb.SetInsertPoint(deadBb);
  }
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);
  if (auto p = obj->dcst<VarDecl>())
    return self(p, true); // global
  ABORT();
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  auto func = llvm::dyn_cast<llvm::Function>(mDeclMap[obj]);
  if (!func)
    ABORT();

  auto fty = func->getFunctionType();

  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& irb = *mCurIrb;

  // Allocate space for parameters and store them
  auto argIt = func->arg_begin();
  for (size_t i = 0; i < obj->params.size() && argIt != func->arg_end(); ++i, ++argIt) {
    auto param = obj->params[i];
    auto vd = param->dcst<VarDecl>();
    if (vd) {
      auto paramTy = self(vd->type);
      auto alloca = createAlloca(paramTy, vd->name);
      irb.CreateStore(&*argIt, alloca);
      mDeclMap[vd] = alloca;
    }
  }

  mCurFunc = func;
  self(obj->body);

  // Ensure the last block has a terminator
  auto& exitIrb = *mCurIrb;
  auto lastBb = exitIrb.GetInsertBlock();
  if (!lastBb->getTerminator()) {
    if (fty->getReturnType()->isVoidTy())
      exitIrb.CreateRetVoid();
    else
      exitIrb.CreateRet(llvm::ConstantInt::get(fty->getReturnType(), 0));
  }
}

void
EmitIR::operator()(VarDecl* obj, bool isGlobal)
{
  auto& irb = *mCurIrb;
  auto ty = self(obj->type);

  if (isGlobal) {
    llvm::Constant* initVal = nullptr;
    if (obj->init) {
      if (auto il = obj->init->dcst<IntegerLiteral>()) {
        initVal = llvm::ConstantInt::get(ty, il->val);
      } else if (auto ile = obj->init->dcst<ImplicitInitExpr>()) {
        initVal = llvm::ConstantInt::get(ty, 0);
      }
    }
    if (!initVal)
      initVal = llvm::ConstantInt::get(ty, 0);

    auto gv = new llvm::GlobalVariable(
      mMod, ty, false, llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    mDeclMap[obj] = gv;
  } else {
    // Local variable
    auto alloca = createAlloca(ty, obj->name);
    mDeclMap[obj] = alloca;

    if (obj->init) {
      storeInit(alloca, obj->init, obj->type);
    }
  }
}

//==============================================================================
// 辅助
//==============================================================================

llvm::Value*
EmitIR::createAlloca(llvm::Type* ty, const std::string& name)
{
  // Allocate at the entry block of the current function
  auto& entryBb = mCurFunc->getEntryBlock();
  llvm::IRBuilder<> entryIrb(&entryBb, entryBb.begin());
  return entryIrb.CreateAlloca(ty, nullptr, name);
}

void
EmitIR::storeInit(llvm::Value* ptr, Expr* init, const Type* type)
{
  auto& irb = *mCurIrb;

  if (auto il = init->dcst<IntegerLiteral>()) {
    irb.CreateStore(llvm::ConstantInt::get(self(type), il->val), ptr);
  } else if (auto ile = init->dcst<ImplicitInitExpr>()) {
    irb.CreateStore(llvm::ConstantInt::get(self(type), 0), ptr);
  } else if (auto initList = init->dcst<InitListExpr>()) {
    // Handle array initialization
    auto arrTy = llvm::dyn_cast<llvm::ArrayType>(self(type));
    if (arrTy) {
      auto elemTy = arrTy->getElementType();
      for (size_t i = 0; i < initList->list.size(); ++i) {
        auto idx = llvm::ConstantInt::get(mIntTy, i);
        auto elemPtr = irb.CreateInBoundsGEP(arrTy, ptr, { llvm::ConstantInt::get(mIntTy, 0), idx });
        storeInit(elemPtr, initList->list[i], type); // recurse with same type (will get sub type)
      }
      // Zero-initialize remaining elements
      for (size_t i = initList->list.size(); i < arrTy->getNumElements(); ++i) {
        auto idx = llvm::ConstantInt::get(mIntTy, i);
        auto elemPtr = irb.CreateInBoundsGEP(arrTy, ptr, { llvm::ConstantInt::get(mIntTy, 0), idx });
        irb.CreateStore(llvm::ConstantInt::get(elemTy, 0), elemPtr);
      }
    }
  } else {
    auto val = emitRValue(init);
    auto targetTy = self(type);
    if (val->getType() != targetTy) {
      if (targetTy->isIntegerTy() && val->getType()->isIntegerTy()) {
        val = irb.CreateIntCast(val, targetTy, true);
      }
    }
    irb.CreateStore(val, ptr);
  }
}

