  auto& irb = *mCurIrb;

  // Get the function - head might be wrapped in ImplicitCastExpr
  Expr* head = obj->head;
  while (auto cast = head->dcst<ImplicitCastExpr>()) {
    head = cast->sub;
  }

  llvm::Value* callee = nullptr;
  if (auto dre = head->dcst<DeclRefExpr>()) {
    callee = self(dre);
  } else {
    callee = emitRValue(head);
  }

  auto func = llvm::dyn_cast<llvm::Function>(callee);

  // Get function type from the head expression's type
  llvm::FunctionType* fty = nullptr;
  if (func) {
    fty = func->getFunctionType();
  } else {
    // Get function type from the head expression's ASG type
    auto headType = head->type;
    if (auto ft = headType->texp->dcst<FunctionType>()) {
      fty = llvm::dyn_cast<llvm::FunctionType>(self(headType));
    }
  }

  std::vector<llvm::Value*> args;
  for (size_t i = 0; i < obj->args.size(); ++i) {
    auto arg = emitRValue(obj->args[i]);
    if (fty && i < fty->getNumParams()) {
      auto paramTy = fty->getParamType(i);
      if (arg->getType() != paramTy) {
        if (paramTy->isIntegerTy() && arg->getType()->isIntegerTy()) {
          arg = irb.CreateIntCast(arg, paramTy, true);
        }
      }
    }
    args.push_back(arg);
  }

  if (func)
    return irb.CreateCall(func, args);
  else
    return irb.CreateCall(fty, callee, args);

