   222	      binaryExpr->op = BinaryExpr::Op::kGt;
   223	    else if (opCode == "<")
   224	      binaryExpr->op = BinaryExpr::Op::kLt;
   225	    else if (opCode == ">=")
   226	      binaryExpr->op = BinaryExpr::Op::kGe;
   227	    else if (opCode == "<=")
   228	      binaryExpr->op = BinaryExpr::Op::kLe;
   229	    else if (opCode == "==")
   230	      binaryExpr->op = BinaryExpr::Op::kEq;
   231	    else if (opCode == "!=")
   232	      binaryExpr->op = BinaryExpr::Op::kNe;
   233	    else if (opCode == "&&")
   234	      binaryExpr->op = BinaryExpr::Op::kAnd;
   235	    else if (opCode == "||")
   236	      binaryExpr->op = BinaryExpr::Op::kOr;
   237	    else if (opCode == "=")
   238	      binaryExpr->op = BinaryExpr::Op::kAssign;
   239	    else {
   240	      ABORT();
   241	    }
   242	  }
   243	
   244	  auto inner = jobj.getArray("inner");
   245	  ASSERT(inner);
   246	
   247	  binaryExpr->lft = expr(*inner->front().getAsObject());
   248	  binaryExpr->rht = expr(*(*inner)[1].getAsObject());
   249	
   250	  return binaryExpr;
   251	}
