   482	// ========================================================================== //
   483	// 类型字符串解析
   484	// ========================================================================== //
   485	
   486	/**
   487	 * 本实验中 `clang -cc1 -ast-dump=json` 输出的类型字符串语法：
   488	 *
   489	 *  type
   490	 *    : base+ texp '\0'
   491	 *    ;
   492	 *  base
   493	 *    : 'void' | 'char' | 'int' | 'long' | 'const'
   494	 *    ;
   495	 *  texp
   496	 *    : texp_2
   497	 *    ;
   498	 *  texp_0
   499	 *    : %empty
   500	 *    | '[' oct ']'
   501	 *    | '(' args ')'
   502	 *    | '(' texp ')'
   503	 *    ;
   504	 *  texp_1
   505	 *    ; texp_0+
   506	 *    ;
   507	 *  texp_2
   508	 *    : '*' texp_2
   509	 *    | texp_1
   510	 *    ;
   511	 *  args
   512	 *    : %empty
   513	 *    | type (',' type)*
   514	 *    ;
   515	 *  oct
   516	 *    : [0-9]+
   517	 *    ;
   518	 *
   519	 * 以下是对应上述文法的手工实现的 LL(1) 递归下降解析器，在学完编译
   520	 * 原理课程后，所有同学都应当掌握手写 LL(1) 递归下降解析器的能力。
   521	 *
   522	 * 容易看出以下的函数在签名上都有相似的模式，例如：
   523	 *   1. 所有函数的第一个参数都是一个字符串指针，指向待解析的字符串开头；
   524	 *   2. 所有函数的返回值都是一个字符串指针，指向解析成功后的剩余字符串开头；
   525	 *   3. 如果解析失败，返回 nullptr；
   526	 *   4. 解析过程的语义值通过额外的引用参数传出。
   527	 * 这些都是实现 LL(1) 递归下降解析器的常规编码范式，遵循范式去实现代码
   528	 * 可以避免常见的误区，极大地提升编码质量。
   529	 */
   530	
   531	namespace {
   532	
   533	const char*
   534	match(const char* s, const char* p)
   535	{
   536	  while (*p) {
   537	    if (*s != *p)
   538	      return nullptr;
   539	    ++s, ++p;
   540	  }
   541	  return s;
   542	}
   543	
   544	const char*
   545	skip_spaces(const char* s)
   546	{
   547	  while (*s == ' ')
   548	    ++s;
   549	  return s;
   550	}
   551	
   552	const char*
   553	parse_base(const char* s, Type& v)
   554	{
   555	  if (auto p = match(s, "void")) {
   556	    ASSERT(v.spec == Type::Spec::kINVALID);
   557	    v.spec = Type::Spec::kVoid;
   558	    return p;
   559	  }
   560	  if (auto p = match(s, "char")) {
   561	    ASSERT(v.spec == Type::Spec::kINVALID);
   562	    v.spec = Type::Spec::kChar;
   563	    return p;
   564	  }
   565	  if (auto p = match(s, "int")) {
   566	    ASSERT(v.spec == Type::Spec::kINVALID);
   567	    v.spec = Type::Spec::kInt;
   568	    return p;
   569	  }
   570	  if (auto p = match(s, "long")) {
   571	    if (v.spec == Type::Spec::kINVALID)
   572	      v.spec = Type::Spec::kLong;
   573	    else if (v.spec == Type::Spec::kLong)
   574	      v.spec = Type::Spec::kLongLong;
   575	    else
   576	      ABORT();
   577	    return p;
   578	  }
   579	  if (auto p = match(s, "const")) {
   580	    v.qual.const_ = true;
   581	    return p;
   582	  }
   583	  return nullptr;
   584	}
   585	
   586	const char*
   587	parse_oct(const char* s, std::uint32_t& v)
   588	{
   589	  if (*s < '0' || *s > '9')
   590	    return nullptr;
   591	  std::uint32_t num = 0;
   592	  while ('0' <= *s && *s <= '9') {
   593	    num = num * 10 + (*s - '0');
   594	    ++s;
   595	  }
   596	  v = num;
   597	  return s;
   598	}
   599	
   600	/// 把 \p texp 的里面翻出来，因为 C 的类型表达式与表达式内外顺序是相反的。
   601	TypeExpr*
   602	turn_texp(TypeExpr* texp)
   603	{
   604	  if (texp->sub == nullptr)
   605	    return texp;
   606	  auto innerMost = turn_texp(texp->sub);
   607	  innerMost->sub = texp;
   608	  texp->sub = nullptr;
   609	  return innerMost;
   610	}
   611	
   612	} // namespace
   613	
   614	const char*
   615	Json2Asg::parse_type(const char* s, const Type*& v)
   616	{
   617	  auto ty = make<Type>();
   618	  s = parse_base(s, *ty);
   619	  if (!s)
   620	    return nullptr;
   621	
   622	  while (true) {
   623	    auto p = parse_base(skip_spaces(s), *ty);
   624	    if (!p)
   625	      break;
   626	    s = p;
   627	  }
   628	
   629	  s = parse_texp(skip_spaces(s), ty->texp);
   630	  if (ty->texp)
   631	    ty->texp = turn_texp(ty->texp); // 将类型表达式内外翻转
   632	
   633	  v = ty;
   634	  return s;
   635	}
   636	
   637	const char*
   638	Json2Asg::parse_texp(const char* s, TypeExpr*& v)
   639	{
   640	  return parse_texp_2(s, v);
   641	}
   642	
   643	const char*
   644	Json2Asg::parse_texp_0(const char* s, TypeExpr*& v)
   645	{
   646	RULE_1:
   647	  if (auto p = match(s, "[")) {
   648	    std::uint32_t len;
   649	    p = parse_oct(skip_spaces(p), len);
   650	    if (!p)
   651	      goto RULE_2;
   652	    p = match(skip_spaces(p), "]");
   653	    if (!p)
   654	      goto RULE_2;
   655	    auto arrTy = make<ArrayType>();
   656	    arrTy->len = len;
   657	    v = arrTy;
   658	    return p;
   659	  }
   660	
   661	RULE_2:
   662	  if (auto p = match(s, "(")) {
   663	    std::vector<const Type*> params;
   664	    p = parse_args(skip_spaces(p), params);
   665	    if (!p)
   666	      goto RULE_3;
   667	    p = match(skip_spaces(p), ")");
   668	    if (!p)
   669	      goto RULE_3;
   670	    auto funTy = make<FunctionType>();
   671	    funTy->params = std::move(params);
   672	    v = funTy;
   673	    return p;
   674	  }
   675	
   676	RULE_3:
   677	  if (auto p = match(s, "(")) {
   678	    p = parse_texp(skip_spaces(p), v);
   679	    if (!p)
   680	      goto EMPTY;
   681	    p = match(skip_spaces(p), ")");
   682	    if (!p)
   683	      goto EMPTY;
   684	    return p;
   685	  }
   686	
   687	EMPTY:
   688	  v = nullptr;
   689	  return s;
   690	}
   691	
   692	const char*
   693	Json2Asg::parse_texp_1(const char* s, TypeExpr*& v)
   694	{
   695	  TypeExpr* texp;
   696	  auto p = parse_texp_0(s, texp);
   697	  if (!p)
   698	    return nullptr;
   699	  if (s != p) {
   700	    while (true) {
   701	      s = p;
   702	      TypeExpr* sup;
   703	      p = parse_texp_0(skip_spaces(p), sup);
   704	      if (!p)
   705	        return nullptr;
   706	      if (s == p)
   707	        break;
   708	      sup->sub = texp;
   709	      texp = sup;
   710	    }
   711	  }
   712	  v = texp;
   713	  return s;
   714	}
   715	
   716	const char*
   717	Json2Asg::parse_texp_2(const char* s, TypeExpr*& v)
   718	{
   719	RULE_1:
   720	  if (auto p = match(s, "*")) {
   721	    TypeExpr* texp;
   722	    p = parse_texp_2(skip_spaces(p), texp);
   723	    if (!p)
   724	      goto EMPTY;
   725	    v = make<PointerType>();
   726	    v->sub = texp;
   727	    return p;
   728	  }
   729	
   730	RULE_2:
   731	  if (auto p = parse_texp_1(s, v))
   732	    return p;
   733	
   734	EMPTY:
   735	  return nullptr;
   736	}
   737	
   738	const char*
   739	Json2Asg::parse_args(const char* s, std::vector<const Type*>& v)
   740	{
   741	  const Type* ty;
   742	  auto p = parse_type(s, ty);
   743	  if (!p)
   744	    return s; // 没有参数的情况也是合法的
   745	  s = p;
   746	
   747	  std::vector<const Type*> params;
   748	  params.push_back(ty);
   749	
   750	  while (true) {
   751	    p = match(skip_spaces(s), ",");
   752	    if (!p)
   753	      break;
   754	
   755	    p = parse_type(skip_spaces(p), ty);
   756	    if (!p)
   757	      return nullptr;
   758	
   759	    params.push_back(ty);
   760	    s = p;
   761	  }
   762	
   763	  v = std::move(params);
   764	  return s;
   765	}
